// Themen-Dedup: erstes Thema wählen, das noch nicht im Archiv steht.
// Top-Ergebnisse der Themen-Recherche aus Tavily
const search = $('Themen-Recherche (Tavily)').first().json;
const results = Array.isArray(search.results) ? search.results : [];

// Bereits behandelte Themen aus dem Archiv (Data Table)
const archiv = $('Archiv laden').all().map(i => i.json);

// Normalisierung: Kleinschreibung, nur aussagekräftige Tokens
const tokenize = (s) => (s || '')
  .toLowerCase()
  .replace(/[^a-z0-9äöüß ]/gi, ' ')
  .split(/\s+/)
  .filter(t => t.length > 3);

const stop = new Set(['oder','und','news','letzte','tage','eine','einen','einer','mit',
  'für','von','das','der','die','dem','den','ein','ist','wird','neue','neuer','neues','beim','über']);
const keyset = (s) => new Set(tokenize(s).filter(t => !stop.has(t)));

// Jaccard-Ähnlichkeit zweier Token-Mengen (0..1)
const jaccard = (a, b) => {
  if (a.size === 0 || b.size === 0) return 0;
  let inter = 0;
  for (const t of a) if (b.has(t)) inter++;
  return inter / (a.size + b.size - inter);
};

// Archiv-Themen als Token-Mengen (Titel + Keywords)
const archivKeys = archiv.map(row => keyset(`${row.title || ''} ${row.keywords || ''}`));

// Kandidaten = Ergebnisse, die thematisch noch nicht im Archiv stehen
const candidates = results.filter(r => {
  const k = keyset(r.title);
  return k.size > 0 && !archivKeys.some(ak => jaccard(k, ak) >= 0.4);
});

// Kein neues Thema gefunden -> Workflow meldet das und bricht sauber ab
if (candidates.length === 0) {
  return [{ json: { has_new_topic: false } }];
}

// Cross-Coverage: wie viele ANDERE Ergebnisse behandeln dasselbe Thema?
// Mehr Überschneidung = Mainstream-Thema = mehr unabhängige Quellen erwartbar.
const scored = candidates.map(c => {
  const ck = keyset(c.title);
  let coverage = 0;
  for (const r of results) {
    if (r.url === c.url) continue;
    if (jaccard(ck, keyset(r.title)) >= 0.2) coverage++;
  }
  return { r: c, coverage, score: c.score || 0 };
});

// Beste Wahl: meiste Überschneidung, dann höchster Tavily-Relevanz-Score
scored.sort((a, b) => (b.coverage - a.coverage) || (b.score - a.score));
const chosen = scored[0].r;

// Tiefen-Recherche breiter abfragen: wichtigste Titel-Stichwörter statt exaktem Titel
const titleTokens = [...keyset(chosen.title)];
const topic_query = titleTokens.slice(0, 6).join(' ') || chosen.title;

return [{ json: {
  has_new_topic: true,
  topic_title: chosen.title,
  topic_url: chosen.url,
  topic_query,
  coverage: scored[0].coverage,
  candidate_count: candidates.length
}}];

// Quellen prüfen (min. 3 unabhängige Domains) + Claude-Prompt aufbauen.
// Ergebnisse der Tiefen-Recherche
const deep = $('Tiefen-Recherche (Tavily)').first().json;
const results = Array.isArray(deep.results) ? deep.results : [];
const topic = $('Themen-Dedup').first().json.topic_title || 'KI-News der Woche';

// Domain aus URL extrahieren
const domainOf = (url) => {
  try { return new URL(url).hostname.replace(/^www\./, ''); }
  catch (e) { return ''; }
};

// Quellen aufbereiten, Duplikate je URL entfernen
const seen = new Set();
const sources = [];
for (const r of results) {
  if (!r.url || seen.has(r.url)) continue;
  seen.add(r.url);
  const content = (r.raw_content || r.content || '').replace(/\s+/g, ' ').trim().substring(0, 2000);
  sources.push({
    url: r.url,
    title: r.title || '',
    published_date: r.published_date || '',
    domain: domainOf(r.url),
    snippet: content
  });
}

// Mindestens 3 verschiedene Domains erforderlich (Anti-Halluzination)
const domains = new Set(sources.map(s => s.domain).filter(Boolean));
const enough_sources = domains.size >= 3 && sources.length >= 3;

// Exakter System-Prompt gemäß Vorgabe
const claude_system = "Du bist Redakteur für den AK-Assistance-Blog. Zielgruppe: deutsche Handwerksbetriebe,\ndie wissen wollen, was in der KI-Welt passiert und was es für sie bedeutet.\n\nStrikte Regeln:\n- Verwende AUSSCHLIESSLICH die unten gelieferten Recherche-Quellen. Keine Information,\n  die dort nicht steht, darf in den Artikel.\n- Wenn die Quellen widersprüchlich oder unklar sind, benenne das im Artikel.\n- Keine Zahlen, Zitate, Studien oder Personen erfinden.\n- Schreibe auf Deutsch, sachlich, klar, ohne Marketing-Floskeln.\n- Länge: 600–900 Wörter.\n- Struktur: H1-Titel, kurze Einleitung (2–3 Sätze), 3–5 H2-Abschnitte, Fazit, Quellenliste.\n- Quellenliste am Ende als nummerierte Liste: [Nr] Titel — Domain (Datum) — URL.\n- Wenn weniger als 3 Quellen verwertbar sind, antworte ausschließlich mit:\n  \"INSUFFICIENT_SOURCES\".\n\nGib das Ergebnis als JSON zurück:\n{\n  \"title\": \"...\",\n  \"slug\": \"...\",\n  \"meta_description\": \"... (max 155 Zeichen, SEO-tauglich)\",\n  \"keywords\": [\"...\", \"...\"],\n  \"body_markdown\": \"...\",\n  \"sources_used\": [{\"url\": \"...\", \"title\": \"...\", \"date\": \"...\"}]\n}";

// User-Message: Thema + komplette Recherche-Quellen (URL, Titel, Datum, Inhalt)
const quellenText = sources.map((s, i) =>
  `[${i + 1}] ${s.title}\nDomain: ${s.domain}\nDatum: ${s.published_date || 'unbekannt'}\nURL: ${s.url}\nInhalt: ${s.snippet}`
).join('\n\n');

const claude_user = `Thema des Artikels: ${topic}\n\n`
  + `Recherche-Quellen (ausschließlich diese verwenden):\n\n${quellenText}`;

return [{ json: {
  enough_sources,
  sources_count: sources.length,
  domains_count: domains.size,
  sources,
  topic_title: topic,
  claude_system,
  claude_user
}}];

// Claude-Antwort parsen und auf Verwertbarkeit prüfen.
const resp = $input.first().json;
const text = (resp.content && resp.content[0] && resp.content[0].text) ? resp.content[0].text : '';

// Anti-Halluzination: zu wenige Quellen -> klares Abbruchsignal
if (text.trim().includes('INSUFFICIENT_SOURCES')) {
  return [{ json: { article_valid: false, reason: 'INSUFFICIENT_SOURCES' } }];
}

// JSON aus der Antwort extrahieren (robust gegen umschließenden Text)
let parsed = null;
try {
  parsed = JSON.parse(text.trim());
} catch (e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (e2) {} }
}

// Pflichtfelder müssen vorhanden sein, sonst gilt der Artikel als ungültig
if (!parsed || !parsed.title || !parsed.body_markdown) {
  return [{ json: { article_valid: false, reason: 'PARSE_ERROR' } }];
}

// Slug absichern (falls Claude keinen liefert)
const slug = parsed.slug || parsed.title.toLowerCase()
  .replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

return [{ json: {
  article_valid: true,
  title: parsed.title,
  slug,
  meta_description: parsed.meta_description || '',
  keywords: Array.isArray(parsed.keywords) ? parsed.keywords : [],
  body_markdown: parsed.body_markdown,
  sources_used: Array.isArray(parsed.sources_used) ? parsed.sources_used : []
}}];

